import { InjectionKey } from 'vue'
import { createStore, useStore as baseUseStore, Store } from 'vuex'
import MailOptions from "@/types/MailOptions";
import Element from "@/types/elements/Element";
import {Country} from "@/types/Country";
import {Language} from "@/types/Language";
import {MessageCategory} from "@/types/MessageCategory";
export interface State {
  snackbar: { active: boolean, color: string, message: string, timer: number, fn?: () => void, fnName?: string },
  mailOptions: MailOptions,
  elementList: Element[],
}

export const key: InjectionKey<Store<State>> = Symbol();

export default createStore<State>({
  state: {
    snackbar: { active: false, color: "", message: "", timer: 5000, fnName: "" },
    mailOptions: new MailOptions(true, 15000, Country.EE, Language.ENG, false, null,
        (new Date()).toLocaleString('et-EE', { month: 'long' }).split(' ').map( w =>  w.substring(0,1).toUpperCase()+ w.substring(1)).join(' ')
        + " " + (new Date().getFullYear()), "", false,"https://www.swedbank.ee/kirjad/"),
    elementList: [],
  },
  getters: {
    mailOptions: function (state) {return state.mailOptions},
    elementList: function (state) {return state.elementList},
  },
  mutations: {
    UPDATE_SNACKBAR(state, snackbar) {
      state.snackbar = snackbar;
    },
    UPDATE_MAIL_OPTIONS(state, mailOptions) {
      state.mailOptions = mailOptions;
    },
    UPDATE_ELEMENT_LIST(state, elementList) {
      state.elementList = elementList;
    }
  },
  actions: {
    showSnack({ commit }, { message, color, timer = 5000, fn = undefined, fnName = '' }) {
      commit("UPDATE_SNACKBAR", {
        active: true,
        color: color,
        message: message,
        timer: timer,
        fn: fn,
        fnName: fnName,
      });
    }
  },
  modules: {
  }
})

export function useStore () {
  return baseUseStore(key)
}
