import { ref, watch } from "vue";

// SSR-safe access to localStorage and default value handling
const getInitial = () => {
  try {
    if (typeof localStorage === "undefined") return true;
    return localStorage.getItem("enable-conditional-outline") === "false"
      ? false
      : true;
  } catch {
    return true;
  }
};

const enableConditionalOutline = ref(getInitial());

watch(enableConditionalOutline, (value) => {
  try {
    localStorage.setItem("enable-conditional-outline", String(value));
  } catch {
    // ignore
  }
});

export default enableConditionalOutline;