import Element from "@/types/elements/Element";

export const getImageUrl = (element: Element) => {
  // Extract options from the props
  const options = element.options;
  // Check if there is at least one image file
  if (options.imageFile.length > 0) {
    try {
      return URL.createObjectURL(options.imageFile[0]);
    }
    // If there is an image file, return its local URL
    catch (e) {
      const blob = b64toBlob(options.imageFileBase64, 'image/png');
      return URL.createObjectURL(blob);
    }
  } else {
    // If there are no image files, return the provided image URL
    return options.imageUrl;
  }
}

export function getImageFromBase64(element: Element) {
  element.options.imageFile[0] = b64toBlob(element.options.imageFileBase64, element.options.fileType);
  element.options.imageFile[0].name = element.options.fileName
}

const b64toBlob = (b64Data: string, contentType='', sliceSize=512) => {
  const byteCharacters = atob(b64Data);
  const byteArrays = [];

  for (let offset = 0; offset < byteCharacters.length; offset += sliceSize) {
    const slice = byteCharacters.slice(offset, offset + sliceSize);

    const byteNumbers = new Array(slice.length);
    for (let i = 0; i < slice.length; i++) {
      byteNumbers[i] = slice.charCodeAt(i);
    }

    const byteArray = new Uint8Array(byteNumbers);
    byteArrays.push(byteArray);
  }

  return new Blob(byteArrays, {type: contentType});
}
