import {getImageUrl} from "@/utils/image/getImageUrl";
import Element from "@/types/elements/Element";

export default async function getImageDimensions(element: Element) {
  const dimensions = await getHeightAndWidthFromDataUrl(getImageUrl(element));
  return `${dimensions.width}x${dimensions.height}`;
}

export function getHeightAndWidthFromDataUrl (dataURL: string): Promise<{ height: number; width: number }> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      resolve({
        height: img.height,
        width: img.width,
      });
    };
    img.src = dataURL;
  });
}