import {Language} from "@/types/Language";

export default function getGreetings(language: Language): string[] {
  return greetingsList[language];
}

const greetingsList: Record<Language, string[]> = {
  "EST": ["Hea $clientName", "Tere", "Tere, $clientName"],
  "ENG": ["Dear $clientName", "Dear representative of $clientName", "Dear customer", "Hello", "Hello, $clientName"],
  "RUS": ["Здравствуйте", "Здравствуйте, $clientName", "Привет", "Привет, $clientName", "Ув. $clientName"],
  "LAT": ["Cienījamais klient!", "Sveicināti!", "Sveiki!"],
  "LIT": ["Gerb. $clientName", "Labas, $clientGreetingName!", "Mielas Kliente,", "Sveiki, $clientGreetingName,"]
};
