import Element from "@/types/elements/Element";
import {Element_Type} from "@/types/elements/ElementTypes";

export default class ItemStore {
  elements: Element[];
  private deletedItems: DeletedItem[] = [];

  constructor(elements: Element[]) {
    this.elements = elements;
  }

  /**
   * Attempts to delete an element with the given ID from the elements list or any of elements' sub-elements.
   * If a matching element is found and deleted, it is recorded in `deletedItems` via `deleteAndStore()`, so it can be recovered.
   *
   * @param {string} id - The unique identifier of the element to delete.
   */
  public deleteElement(id: string): void {
    this.deleteAndStore(id, this.elements) ||
    this.elements.filter(x => x.subElements).forEach(e =>
      (e.type === Element_Type.TWO_COLUMNS && e.subElements?.forEach(cb => this.deleteAndStore(id, cb.subElements, cb))) ||
      this.deleteAndStore(id, e.subElements, e));
  }

  /**
   * Searches for an element with the given ID in the provided list and deletes and stores it if found.
   *
   * @returns {boolean} `true` if the element was found and deleted; `false` otherwise.
   */
  private deleteAndStore(id: string, elements?: Element[], parent?: Element): boolean {
    if (!elements) return false;
    return elements.some((element, index) => {
      if (element.id === id) {
        elements.splice(index, 1);
        this.deletedItems.push(new DeletedItem(element, index, parent));
        return true;
      }
    })
  }

  public restoreLastDeletedElement() {
    if (this.deletedItems.length == 0) return;
    const deletedItem = this.deletedItems.pop();
    if (deletedItem?.parentElement) deletedItem.parentElement?.subElements?.splice(deletedItem.index, 0, deletedItem.element);
    else this.elements.splice(deletedItem!.index, 0, deletedItem!.element);
  }
}

class DeletedItem {
  element: Element;
  index: number;
  parentElement?: Element = undefined;

  constructor(element: Element, index: number, parentElement?: Element) {
    this.element = element;
    this.index = index;
    this.parentElement = parentElement;
  }
}
