// Styles
import '@mdi/font/css/materialdesignicons.css'
import 'vuetify/styles'

// Vuetify
import { createVuetify } from 'vuetify'

export default createVuetify({
    defaults: {
        VBtn: {
            variant: 'outlined',
        },
        VCheckbox: {
            density: 'comfortable'
        },
        VCombobox: {
            variant: 'outlined',
        },
        VFileInput: {
            variant: 'outlined',
        },
        VSelect: {
            variant: 'outlined',
        },
        VTextarea: {
            variant: 'outlined',
            clearable: true,
        },
        VTextField: {
            variant: 'outlined',
            clearable: true,
        },
        VColorPicker: {
            showSwatches: true,
            hideInputs: true,
            hideSliders: true,
            hideCanvas: true,
            elevation: 0,
        },
        VAppBar: {
            VBtn: { variant: 'outlined'}
        },
        VCardActions: {
            VBtn: { variant: 'outlined'}
        },
        VToolbar: {
            VBtn: { variant: 'outlined'}
        },
    },
    // https://vuetifyjs.com/en/introduction/why-vuetify/#feature-guides
    theme: {
        defaultTheme: "light"
    }
})
