import {Template} from "@/types/Template";
import {Element_Type} from "@/types/elements/ElementTypes";
import Element from "@/types/elements/Element";
import createElement from "@/utils/createElement";
import {Language} from "@/types/Language";
import {Country} from "@/types/Country";

/**
 * Retrieves an array of elements based on the specified template, language, and country.
 *
 * @param {Template} template - The template type.
 * @param {Language} language - The language for element creation.
 * @param {Country} country - The country for element creation.
 * @returns {Element[]} An array of elements generated from the specified template, language, and country.
 */
export default function getElementsFromTemplate(template: Template, language: Language, country: Country): Element[] {
  const defaultElements: Element_Type[] = getDefaultElementTypesForTemplate(template);
  const elements: Element[] = []
  defaultElements.forEach(element_type => elements.push(structuredClone(createElement(element_type, language, country))));
  if (template === Template.CAMPAIGN) {
    let id = 0;
    const colors = ['#ffecff', '#fdf6ee', '#ecf9f3']
    elements.filter(e => e.type === Element_Type.COLOR_BLOCK).forEach(e => e.options.color = colors[id++ % 3])
  }
  return elements;
}

/**
 * Returns default list of elements based on the specified template.
 *
 * @param {Template} template - The template type.
 * @returns {Element_Type[]} An array of default elements for the given template.
 */
export function getDefaultElementTypesForTemplate(template: Template): Element_Type[] {
  switch (template) {
    case Template.TEXT_ONLY:
      return [Element_Type.LOGO, Element_Type.INTRO, Element_Type.TEXT, Element_Type.SIGNATURE, Element_Type.DISCLAIMER];
    case Template.SIMPLE:
      return [Element_Type.LOGO, Element_Type.INTRO, Element_Type.TEXT, Element_Type.COLOR_BLOCK, Element_Type.TEXT, Element_Type.SIGNATURE, Element_Type.DISCLAIMER];
    case Template.CAMPAIGN:
      return [Element_Type.LOGO, Element_Type.INTRO, Element_Type.TEXT, Element_Type.SIGNATURE, Element_Type.COLOR_BLOCK,
        Element_Type.COLOR_BLOCK, Element_Type.COLOR_BLOCK, Element_Type.TEXT, Element_Type.DISCLAIMER];
    case Template.EMPTY:
    default:
      return [];
  }
}
